import json, urllib.request
urls={
'pr':'https://api.github.com/repos/stainlu/hermes-labyrinth/pulls/7',
'issue_comments':'https://api.github.com/repos/stainlu/hermes-labyrinth/issues/7/comments',
'reviews':'https://api.github.com/repos/stainlu/hermes-labyrinth/pulls/7/reviews',
'review_comments':'https://api.github.com/repos/stainlu/hermes-labyrinth/pulls/7/comments',
'check_runs':'https://api.github.com/repos/stainlu/hermes-labyrinth/commits/main/check-runs'
}
for k,u in urls.items():
    req=urllib.request.Request(u, headers={'Accept':'application/vnd.github+json','User-Agent':'hermes-cron'})
    with urllib.request.urlopen(req, timeout=30) as r:
        data=json.load(r)
    print(f'=== {k} ===')
    if k=='pr':
        out={x:data.get(x) for x in ['state','merged','mergeable_state','draft','head','base','statuses_url','review_comments','comments','commits','updated_at']}
        print(json.dumps(out, indent=2))
    else:
        if isinstance(data,list):
            print('count',len(data))
            for item in data[-5:]:
                if k=='issue_comments':
                    print(json.dumps({'id':item['id'],'user':item['user']['login'],'created_at':item['created_at'],'body':item['body'][:180]},indent=2))
                elif k=='reviews':
                    print(json.dumps({'id':item['id'],'user':item['user']['login'],'state':item['state'],'submitted_at':item.get('submitted_at'),'body':(item.get('body') or '')[:180]},indent=2))
                elif k=='review_comments':
                    print(json.dumps({'id':item['id'],'user':item['user']['login'],'path':item['path'],'created_at':item['created_at'],'body':item['body'][:180]},indent=2))
        else:
            print(json.dumps(data, indent=2)[:800])
